INSERT INTO `profiles` VALUES (1,41,'',NULL,'<p style=\"text-align: justify;\"><span style=\"font-weight: 700; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; font-size: 16px;\">TUGAS</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14px;\">Depot Arsip Berkelanjutan ANRI di Provinsi Jawa Barat mempunyai tugas melaksanakan penyelamatan, pengolahan, pelestarian dan pelindungan serta layanan dan pemanfaatan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: bold; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; font-size: 16px;\">FUNGSI</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role=\"list\"><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">Pelaksanaan koordinasi dengan unit kerja Arsip Nasional Republik Indonesia dan instansi terkait dalam rangka melaksanakan tugas dan fungsinya;</span></li><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">pelaksanaan penyelamatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">pelaksanaan pengolahan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">pelaksanaan pelestarian dan pelindungan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat; dan</span></li><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">pelaksanaan layanan dan pemanfaatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style=\"text-align: justify; color: rgb(0, 204, 255);\"><a href=\"https://kearsipan.undip.ac.id/download/\" target=\"_blank\" style=\"color: rgb(0, 204, 255); font-size: 14px; font-weight: bold;\">Unduh Undang-Undang No. 43 Tahun 2009 tentang Kearsipan dan Peraturan Pemerintah No. 28 Tahun 2012 Tentang Pelaksanaan.</a></div>','<p style=\"text-align: justify;\"><span style=\"font-weight: 700; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; 16px;\">TASK</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14px;\">The ANRI Sustainable Archives Depot in West Java Province has the task of carrying out the rescue, processing, preservation and protection as well as services and utilization of static archives of central state institutions in the West Java Province region.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: bold; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; 16px;\">FUNCTION</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role=\"list\"><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">Implementation of coordination with the work unit of the National Archives of the Republic of Indonesia and related agencies in order to carry out their duties and functions; and static archives of central level state institutions in West Java Province; 14px;\">implementation of preservation and protection of inactive archives that have sustainable value and static archives of central state institutions in the West Java Province region; and</span></li><li style=\"text-align: justify; white-space: pre-wrap;\"><span style=\"font-size: 14px;\">implementation of services and utilization of inactive archives that have ongoing value and static archives of central state institutions in the West Java Province region.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style=\"text-align: justify; color: rgb(0, 204, 255);\"><a href=\"https://kearsipan.undip.ac.id/download/\" target=\"_blank\" style=\"color: rgb(0, 204, 255); font-size: 14px; font-weight: bold;\">Download Law no. 43 of 2009 concerning Archives and Government Regulation no. 28 of 2012 concerning Implementation.</a></div>','tugas_fungsi',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,2,'2026-04-09 20:00:50','2026-04-15 19:59:42'),(2,41,'',NULL,'<p>\r\n</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-weight: 700; text-decoration: underline; font-size: 16px\">TUGAS</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-size: 14px\">Depot Arsip Berkelanjutan ANRI di Provinsi Jawa Barat mempunyai tugas melaksanakan penyelamatan, pengolahan, pelestarian dan pelindungan serta layanan dan pemanfaatan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-weight: bold; text-decoration: underline; font-size: 16px\">FUNGSI</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role=\"list\" style=\" margin: 1em 0px; padding-left: 1.5rem; list-style-type: decimal\"><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">Pelaksanaan koordinasi dengan unit kerja Arsip Nasional Republik Indonesia dan instansi terkait dalam rangka melaksanakan tugas dan fungsinya;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">pelaksanaan penyelamatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">pelaksanaan pengolahan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">pelaksanaan pelestarian dan pelindungan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat; dan</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">pelaksanaan layanan dan pemanfaatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style=\" color: rgb(0, 204, 255); font-size: 1rem; line-height: 1.75; text-align: justify\"><a href=\"https://kearsipan.undip.ac.id/download/\" target=\"_blank\" style=\" color: rgb(0, 204, 255); text-decoration: none; transition: color 0.2s; font-size: 14px; font-weight: bold\">Unduh Undang-Undang No. 43 Tahun 2009 tentang Kearsipan dan Peraturan Pemerintah No. 28 Tahun 2012 Tentang Pelaksanaan.</a></div>','<p>\r\n</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-weight: 700; text-decoration: underline; font-size: 16px\">TASK</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-size: 14px\">The ANRI Sustainable Archives Depot in West Java Province has the task of carrying out the rescue, processing, preservation and protection as well as services and utilization of static archives of central state institutions in the West Java Province region.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify\"><span style=\" font-weight: bold; text-decoration: underline; font-size: 16px\">FUNCTION</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role=\"list\" style=\" margin: 1em 0px; padding-left: 1.5rem; list-style-type: decimal\"><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">Implementation of coordination with the work units of the National Archives of the Republic of Indonesia and related agencies in order to carry out their duties and functions;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">implementation of saving inactive archives that have ongoing value and static archives of central level state institutions;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; 14px\">implementation of processing of inactive archives which have ongoing value and static archives of central level state institutions in the West Java Province region;</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">implementation of preservation and protection of inactive archives which have ongoing value and static archives of central level state institutions in the West Java Province region; and</span></li><li style=\" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap\"><span style=\" font-size: 14px\">implementation of services and utilization of inactive archives that have ongoing value and static archives of central state institutions in the West Java Province region.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style=\" color: rgb(0, 204, 255); font-size: 1rem; line-height: 1.75; text-align: justify\"><a href=\"https://kearsipan.undip.ac.id/download/\" target=\"_blank\" style=\" color: rgb(0, 204, 255); text-decoration: none; transition: color 0.2s; font-size: 14px; font-weight: bold\">Download Law no. 43 of 2009 concerning Archives and Government Regulation no. 28 of 2012 concerning Implementation.</a></div>','tugas_fungsi',NULL,NULL,NULL,NULL,NULL,NULL,'[\"features/profile/DQ68brYAeP2f7qAYnGLIStKuVn3OHJEqRZ8EtvU0.png\", \"features/profile/P8PpSNocGdLWyAA9RY6DnQpCaheZOYYx8TNWBg3n.png\"]','[{\"width\": \"128\", \"height\": \"121\", \"offsetX\": \"170\", \"offsetY\": \"22\", \"position\": \"51.79% 46.06%\"}, {\"width\": \"167\", \"height\": \"156\", \"offsetX\": \"207\", \"offsetY\": \"194\", \"position\": \"50% 50%\"}]',1,'2026-04-15 19:59:42','2026-04-20 20:44:57');
