INSERT INTO `settings` VALUES (1,'disclaimer_content','<p style=\"text-align: justify; margin-bottom: 0.5rem;\"><strong>Disclaimer:</strong> Seluruh informasi, dokumen, dan arsip digital yang tersedia di situs web Depot Arsip Berkelanjutan Bandung (DABB) disajikan berdasarkan data saat informasi itu dibuat semata-mata untuk tujuan pelestarian sejarah, edukasi, dan informasi umum.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\">Dengan mengakses dan menggunakan situs web ini, Anda menyetujui ketentuan berikut:</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\"><strong>Akurasi dan Konteks Historis:</strong> DABB berupaya semaksimal mungkin untuk menjaga keaslian visual dan tekstual dari setiap arsip yang didigitalkan. Namun, kami tidak memberikan jaminan mutlak atas kelengkapan, keakuratan, atau relevansi informasi di dalam dokumen tersebut dengan kondisi masa kini. Arsip historis mungkin memuat pandangan, bahasa, atau norma pada masanya yang tidak selalu mencerminkan nilai dan pandangan DABB saat ini.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\"><strong>Hak Cipta dan Penggunaan Publik:</strong> Sebagian besar materi yang ditampilkan mungkin dilindungi oleh hak cipta dari masing-masing pembuat, organisasi asal, atau pemilik sah sebelumnya. Pengunjung diperbolehkan menggunakan arsip untuk keperluan studi dan penelitian pribadi. Penggunaan, reproduksi, atau distribusi ulang untuk tujuan komersial tanpa izin tertulis yang sah sangat dilarang.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 0px;\"><strong>Batasan Tanggung Jawab:</strong> Segala tindakan atau keputusan yang diambil berdasarkan informasi dari arsip di situs web ini sepenuhnya merupakan risiko dan tanggung jawab pengguna. DABB dan seluruh pihak pengelola tidak bertanggung jawab atas segala bentuk kerugian, baik langsung maupun tidak langsung, yang timbul dari penggunaan atau ketidakmampuan dalam mengakses repositori ini.</p>','2026-03-14 14:07:45','2026-04-23 19:53:34'),(2,'disclaimer_content_en','<p style=\"text-align: justify; margin-bottom: 0.5rem;\"><strong>Disclaimer:</strong> All information, documents and digital archives available on the Bandung Sustainable Archives Depot (DABB) website are presented based on data when the information was created solely for the purposes of historical preservation, education and general information.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\">By accessing and using this website, you agree to the following terms:</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\"><strong>Historical Accuracy and Context:</strong> DABB makes every effort to maintain the visual and textual authenticity of each digitized archive. However, we do not provide absolute guarantees regarding the completeness, accuracy or relevance of the information in the document to current conditions. Historical archives may contain views, language or norms of their time that do not necessarily reflect DABB\'s current values and views.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 1rem;\"><strong>Copyright and Public Use:</strong> Much of the material displayed may be protected by copyright of its respective author, originating organization, or previous legal owner. Visitors are permitted to use the archives for personal study and research purposes. Use, reproduction, or redistribution for commercial purposes without valid written permission is strictly prohibited.</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=\"text-align: justify; margin-bottom: 0px;\"><strong>Limitation of Liability:</strong> Any action or decision taken based on information from the archives on this website is entirely at the user\'s risk and responsibility. DABB and all management parties are not responsible for any form of loss, whether direct or indirect, arising from the use of or inability to access this repository.</p>','2026-03-14 14:07:46','2026-04-23 19:53:35'),(3,'footer_title','DEPOT ARSIP BERKELANJUTAN BANDUNG','2026-03-17 02:50:01','2026-03-17 02:55:13'),(4,'footer_title_en','BANDUNG SUSTAINABLE ARCHIVES DEPOT','2026-03-17 02:50:01','2026-03-17 02:55:15'),(5,'footer_address','Jl. Raya Derwati, Mekarjaya, Kec. Rancasari, Kota Bandung, Jawa Barat 40292','2026-03-17 02:50:01','2026-03-17 02:55:15'),(6,'footer_address_en','Jl. Raya Derwati, Mekarjaya, District. Rancasari, Bandung City, West Java 40292','2026-03-17 02:50:01','2026-03-17 02:55:16'),(7,'footer_phone','+62 21 7805851','2026-03-17 02:50:01','2026-03-17 02:55:16'),(8,'footer_email','info@anri.go.id','2026-03-17 02:50:01','2026-03-17 02:55:16'),(9,'footer_hours','Senin-Kamis : 7:30 - 16:00\r\nJumat : 7:30 - 16:30','2026-03-17 02:50:01','2026-03-17 02:55:16'),(10,'footer_hours_en','Monday-Thursday : 7:30 - 16:00\r\nFriday : 7:30 - 16:30','2026-03-17 02:50:01','2026-03-17 02:55:17'),(11,'footer_managed_by','Depot Arsip Berkelanjutan Bandung','2026-03-17 02:50:01','2026-03-17 02:55:17'),(12,'footer_managed_by_en','Bandung Sustainable Archives Depot','2026-03-17 02:50:01','2026-03-17 02:55:18'),(13,'footer_managed_by_sub',NULL,'2026-03-17 02:50:01','2026-03-17 02:50:01'),(14,'footer_managed_by_sub_en','','2026-03-17 02:50:01','2026-03-17 02:50:01'),(15,'footer_facebook','https://web.facebook.com/ArsipNasionalRI/?locale=id_ID&_rdc=1&_rdr#','2026-03-17 0