INSERT INTO `virtual_book_pages` VALUES (1,26,'Sejarah','History','Gambar tersebut menceritakan seorang pahlawan yang berjuang.','The picture tells of a hero who struggles.',NULL,'[\"features/virtual-books/K5ct5XSTLr1pLJ7rphoK7rbXomOlcn8MCWxyN3n2.png\", \"features/virtual-books/p2YPUeMR1CdISXEjjcCThjGzjH50mRMM5RnXycg4.png\"]','[{\"x\": \"0\", \"y\": \"3.333332994249166\"}, {\"x\": \"49.333329987702776\", \"y\": \"3.333332994249166\"}]','{\"x\": \"3.9925670035422764\", \"y\": \"48.32777421795916\", \"width\": \"85\", \"height\": \"20.3334\"}',NULL,50,'contained',0,0,0,1,'2026-03-11 02:54:32','2026-03-11 02:54:32',NULL),(3,26,'Slide 1','Slide 1',NULL,NULL,NULL,'[\"features/virtual-books/uiv62wUa7ltZUHvF9yAaoWGwIAHvHHlpEXuU2dQF.png\"]','[{\"x\": 0, \"y\": 0.5263157894736842}]','{\"x\": \"11.11111111111111\", \"y\": \"38\", \"width\": \"77.8889\", \"height\": \"15\"}','features/virtual-books/thumbnails/page_thumb_1776869090_69e8dee2d5f67.png',100,'fullbleed',0,0,0,1,'2026-03-12 00:10:50','2026-04-22 08:10:49',8),(4,26,'Slide 2','Slide 2',NULL,NULL,NULL,'[\"features/virtual-books/ec5G8R6fApgnCjCAJ9Kgen7UxMujs0OURzfkQxfd.png\"]','[{\"x\": 0, \"y\": 0}]','{\"x\": \"5.208317683293269\", \"y\": \"59.52485335500617\", \"width\": \"87.2222\", \"height\": \"19\"}','features/virtual-books/thumbnails/page_thumb_1776869225_69e8df692b7b7.png',100,'fullbleed',0,0,0,2,'2026-03-12 00:14:44','2026-04-22 08:00:49',8),(6,26,'Slide 3','Slide 3',NULL,NULL,NULL,'[\"features/virtual-books/BCKJOs2fOLoDIt4VLjb4GcFzrpFeNGf5uXLJ1Cuu.png\"]','[{\"x\": 0, \"y\": 0}]','{\"x\": \"0\", \"y\": \"0\", \"width\": \"45\", \"height\": \"30\"}','features/virtual-books/thumbnails/page_thumb_1776871599_69e8e8af75267.png',100,'fullbleed',0,0,0,3,'2026-03-14 20:25:05','2026-04-22 08:35:30',8),(7,26,'Slide 4','Slide 4',NULL,NULL,NULL,'[\"features/virtual-books/RFlQGT07GnS4nQVPnBVmngmLKYDnHw7dc69fbBoj.png\"]','[{\"x\": \"0\", \"y\": \"0\"}]','{\"x\": \"0\", \"y\": \"0\", \"width\": \"45\", \"height\": \"30\"}','features/virtual-books/thumbnails/page_thumb_1776871927_69e8e9f76e369.png',100,'fullbleed',0,0,0,4,'2026-04-22 08:32:08','2026-04-22 08:32:08',8),(8,26,'Slide 5','Slide 5',NULL,NULL,NULL,'[\"features/virtual-books/TtZBZzawQA7qQXb2KvF018GyDCBtATpooVrd5Y7n.png\"]','[{\"x\": 0, \"y\": 0}]','{\"x\": 0, \"y\": 0, \"width\": 45, \"height\": 30}','features/virtual-books/thumbnails/page_thumb_1776872055_69e8ea779f743.png',100,'fullbleed',0,0,0,5,'2026-04-22 08:34:15','2026-04-22 08:34:15',8),(9,26,'Slide 6','Slide 6',NULL,NULL,NULL,'[\"features/virtual-books/K2BZzRbO5Ef8OQLuVvbFyU9Q3g3B34OHovhX1fIZ.png\"]','[{\"x\": 0, \"y\": 0}]','{\"x\": 0, \"y\": 0, \"width\": 45, \"height\": 30}','features/virtual-books/thumbnails/page_thumb_1776872331_69e8eb8b34d20.png',100,'fullbleed',0,0,0,6,'2026-04-22 08:38:51','2026-04-22 08:38:51',8),(10,26,'Proklamasi Kemerdekaan (1945)','Proclamation of Independence (1945)','Pada 17 Agustus 1945, Soekarno dan Hatta membacakan teks proklamasi di Jakarta. Peristiwa ini menandai lahirnya Republik Indonesia.','On August 17 1945, Soekarno and Hatta read the text of the proclamation in Jakarta. This event marked the birth of the Republic of Indonesia.',NULL,'[\"features/virtual-books/giV9XOlkx3FSBp0MkrUzQgXs4uscIFpHIpCzK8z2.jpg\"]','[{\"x\": \"11.985187989285754\", \"y\": \"2.666666395399333\"}]','{\"x\": \"0\", \"y\": \"57.66110660185683\", \"width\": \"100\", \"height\": \"29.3334\"}','features/virtual-books/thumbnails/page_thumb_1776872866_69e8eda254f42.png',75,'contained',0,0,0,1,'2026-04-22 08:47:46','2026-04-22 08:47:46',7),(11,26,'Kerajaan Majapahit (1293–1500)','Majapahit Kingdom (1293–1500)','Majapahit adalah kerajaan besar di Jawa Timur yang mencapai puncak kejayaan di bawah Hayam Wuruk dan Gajah Mada.','Majapahit was a large kingdom in East Java that reached the peak of glory under Hayam Wuruk and Gajah Mada.',NULL,'[\"features/virtual-books/0Naee2gDQ8Hsr2k8QZQIEfvgXKT3Ea8WFKZOEprh.webp\"]','[{\"x\": 8.104166666666666, \"y\": 0}]','{\"x\": \"3.111111111111111\", \"y\": \"51.33333333333333\", \"width\": \"94.3333\", \"height\": \"36.3333\"}','features/virtual-books/thumbnails/page_thumb_1776874205_69e8f2ddc7fe4.png',84,'contained',0,0,0,2,'2026-04-22 09:06:34','2026-04-22 09:10:05',7),(12,26,'Kolonialisme Belanda','Dutch Colonialism','Belanda mulai menguasai Nusantara sejak abad ke-17 melalui VOC. Sistem tanam paksa dan eksploitasi sumber daya menyebabkan penderitaan rakyat.','The Dutch began to control the archipelago in the 17th century through the VOC. The system of forced cultivation and exploitation of resources causes suffering to the people.',NULL,'[\"features/virtual-books/f2NXFhjaq0t0ejjLjG4JZclTuJ3JbCHvEUFdcZOf.jpg\"]','[{\"x\": \"12.444444444444445\", \"y\": \"0\"}]','{\"x\": \"0\", \"y\": \"49.666666666666664\", \"width\": \"100\", \"height\": \"32.6667\"}','features/virtual-books/thumbnails/page_thumb_1776874361_69e8f379499d2.png',74,'contained',0,0,0,3,'2026-04-22 09:12:41','2026-04-22 09:12:41',7),(13,26,'Pergerakan Nasional (1908–1945)','National Movement (1908–1945)','Dimulai dengan berdirinya Budi Utomo (1908), pergerakan nasional melahirkan organisasi seperti Sarekat Islam dan PNI. Sumpah Pemuda 1928 menjadi simbol persatuan bangsa.','Starting with the founding of Budi Utomo (1908), the national movement gave birth to organizations such as Sarekat Islam and PNI. The 1928 Youth Pledge became a symbol of national unity.',NULL,'[\"features/virtual-books/P5ymgYPAb4le50bUDiO8FMjpUa7y7XmztThZMvU5.webp\"]','[{\"x\": \"5.333333333333334\", \"y\": \"0\"}]','{\"x\": \"0.8888888888888888\", \"y\": \"57.99999999999999\", \"width\": \"100\", \"height\": \"32.3333\"}','features/virtual-books/thumbnails/page_thumb_1776874732_69e8f4ec339f2.png',90,'contained',0,0,0,4,'2026-04-22 09:18:52','2026-04-22 09:18:52',7);
